import{c as t,Q as a,j as i,m as r}from"./chunks/framework.BXc4yaFE.js";const p=JSON.parse('{"title":"OpenAI GPT-5 System Card","description":"","frontmatter":{"title":"OpenAI GPT-5 System Card","authors":"OpenAI (485+ authors, including Sam Altman, Boaz Barak, Aleksander Madry)","published":"2026-01-08T00:00:00.000Z","source":"https://arxiv.org/abs/2601.03267"},"headers":[],"relativePath":"research/papers/2026-01-08-gpt5-system-card-2601-03267.md","filePath":"research/papers/2026-01-08-gpt5-system-card-2601-03267.md","lastUpdated":1779901665000}'),n={name:"research/papers/2026-01-08-gpt5-system-card-2601-03267.md"};function o(s,e,l,d,h,c){return a(),i("div",null,[...e[0]||(e[0]=[r('<h1 id="openai-gpt-5-system-card" tabindex="-1">OpenAI GPT-5 System Card <a class="header-anchor" href="#openai-gpt-5-system-card" aria-label="Permalink to &quot;OpenAI GPT-5 System Card&quot;">​</a></h1><p><strong>Authors</strong>: OpenAI (485+ contributors) <strong>Released (model)</strong>: August 13, 2025 <strong>arXiv Submitted</strong>: December 19, 2025 (appeared January 2026) <strong>arXiv v2</strong>: May 1, 2026 <strong>Source</strong>: <a href="https://arxiv.org/abs/2601.03267" target="_blank" rel="noreferrer">https://arxiv.org/abs/2601.03267</a><strong>arXiv ID</strong>: 2601.03267 <strong>Categories</strong>: cs.CL <strong>License</strong>: CC BY 4.0</p><hr><h2 id="abstract" tabindex="-1">Abstract <a class="header-anchor" href="#abstract" aria-label="Permalink to &quot;Abstract&quot;">​</a></h2><p>GPT-5 is a unified system combining a fast primary model for routine queries and a deeper reasoning model for complex problems, with a real-time router selecting between them. The system demonstrates improvements in hallucination reduction and instruction following, features &quot;safe-completions&quot; safety training, and classifies the reasoning model as High capability in biological and chemical domains under OpenAI&#39;s Preparedness Framework.</p><hr><h2 id="architecture" tabindex="-1">Architecture <a class="header-anchor" href="#architecture" aria-label="Permalink to &quot;Architecture&quot;">​</a></h2><p>GPT-5 consists of multiple models operating as a unified system:</p><table tabindex="0"><thead><tr><th>Model</th><th>Role</th></tr></thead><tbody><tr><td>gpt-5-main</td><td>Fast model for most queries</td></tr><tr><td>gpt-5-main-mini</td><td>Fallback when usage limits reached</td></tr><tr><td>gpt-5-thinking</td><td>Deep reasoning for hard problems</td></tr><tr><td>gpt-5-thinking-mini</td><td>Cost-efficient reasoning</td></tr><tr><td>gpt-5-thinking-nano</td><td>Minimal-cost reasoning</td></tr><tr><td>gpt-5-thinking-pro</td><td>Maximum reasoning effort</td></tr></tbody></table><p><strong>Real-time router</strong>: Selects model based on conversation type, complexity, tool needs, and explicit intent. Continuously improved through user feedback.</p><hr><h2 id="key-safety-innovation-safe-completions-training" tabindex="-1">Key Safety Innovation: Safe-Completions Training <a class="header-anchor" href="#key-safety-innovation-safe-completions-training" aria-label="Permalink to &quot;Key Safety Innovation: Safe-Completions Training&quot;">​</a></h2><p>Rather than binary refusal approaches, GPT-5 implements <strong>output-centric safety training</strong> that &quot;maximizes helpfulness subject to the safety policy&#39;s constraints.&quot; This is particularly beneficial in dual-use domains (biology, cybersecurity): instead of refusing, the model completes the request safely.</p><hr><h2 id="safety-evaluation-results" tabindex="-1">Safety Evaluation Results <a class="header-anchor" href="#safety-evaluation-results" aria-label="Permalink to &quot;Safety Evaluation Results&quot;">​</a></h2><h3 id="disallowed-content" tabindex="-1">Disallowed Content <a class="header-anchor" href="#disallowed-content" aria-label="Permalink to &quot;Disallowed Content&quot;">​</a></h3><ul><li>gpt-5-thinking offline benchmarks: 0.881–1.000 scores (near-perfect)</li><li>Production benchmarks (harder): 0.755–0.958 range</li></ul><h3 id="hallucination-reduction" tabindex="-1">Hallucination Reduction <a class="header-anchor" href="#hallucination-reduction" aria-label="Permalink to &quot;Hallucination Reduction&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Model</th><th>Improvement vs. baseline</th></tr></thead><tbody><tr><td>gpt-5-main</td><td>26% fewer hallucinations than GPT-4o</td></tr><tr><td>gpt-5-thinking</td><td>65% fewer than OpenAI o3</td></tr><tr><td>Response-level major errors (gpt-5-main)</td><td>-44% vs GPT-4o</td></tr><tr><td>Response-level major errors (gpt-5-thinking)</td><td>-78% vs o3</td></tr></tbody></table><h3 id="sycophancy-reduction" tabindex="-1">Sycophancy Reduction <a class="header-anchor" href="#sycophancy-reduction" aria-label="Permalink to &quot;Sycophancy Reduction&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Model</th><th>Score</th><th>Baseline</th></tr></thead><tbody><tr><td>gpt-5-main</td><td>0.052 (offline)</td><td>GPT-4o: 0.145</td></tr><tr><td>Free users (online)</td><td>-69%</td><td>—</td></tr><tr><td>Paid users (online)</td><td>-75%</td><td>—</td></tr></tbody></table><h3 id="jailbreak-resistance" tabindex="-1">Jailbreak Resistance <a class="header-anchor" href="#jailbreak-resistance" aria-label="Permalink to &quot;Jailbreak Resistance&quot;">​</a></h3><p>gpt-5-thinking: 0.995–0.999 not_unsafe scores across violence, abuse, and sexual content categories.</p><h3 id="deception-rates" tabindex="-1">Deception Rates <a class="header-anchor" href="#deception-rates" aria-label="Permalink to &quot;Deception Rates&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Scenario</th><th>gpt-5-thinking</th><th>OpenAI o3</th></tr></thead><tbody><tr><td>Coding deception</td><td>0.17</td><td>0.47</td></tr><tr><td>Browsing broken tools</td><td>0.11</td><td>0.61</td></tr><tr><td>Production monitoring</td><td>~2.1%</td><td>~4.8%</td></tr></tbody></table><hr><h2 id="preparedness-framework-assessment" tabindex="-1">Preparedness Framework Assessment <a class="header-anchor" href="#preparedness-framework-assessment" aria-label="Permalink to &quot;Preparedness Framework Assessment&quot;">​</a></h2><h3 id="biological-chemical-capabilities-high-precautionary" tabindex="-1">Biological &amp; Chemical Capabilities: <strong>High (precautionary)</strong> <a class="header-anchor" href="#biological-chemical-capabilities-high-precautionary" aria-label="Permalink to &quot;Biological &amp; Chemical Capabilities: **High (precautionary)**&quot;">​</a></h3><p>OpenAI designated gpt-5-thinking as High capability despite lacking &quot;definitive evidence&quot; that the model helps novices create severe biological harm:</p><ul><li>Long-form biorisk questions: synthesized information across all five threat creation stages</li><li>Multimodal virology troubleshooting: <strong>exceeded median expert baseline (22.1%)</strong></li><li>ProtocolQA open-ended: underperformed PhD expert consensus (54%)</li><li>TroubleshootingBench: marginally above OpenAI o3</li></ul><h3 id="cybersecurity-capabilities-does-not-meet-high-threshold" tabindex="-1">Cybersecurity Capabilities: <strong>Does not meet High threshold</strong> <a class="header-anchor" href="#cybersecurity-capabilities-does-not-meet-high-threshold" aria-label="Permalink to &quot;Cybersecurity Capabilities: **Does not meet High threshold**&quot;">​</a></h3><ul><li>CTF challenges: comparable to prior models, no significant improvement</li><li>Cyber Range scenarios: unable to solve challenges unaided</li><li>Pattern Labs: 51% evasion success, 35% vulnerability discovery, 49% network simulation</li></ul><h3 id="ai-self-improvement-does-not-meet-high-threshold" tabindex="-1">AI Self-Improvement: <strong>Does not meet High threshold</strong> <a class="header-anchor" href="#ai-self-improvement-does-not-meet-high-threshold" aria-label="Permalink to &quot;AI Self-Improvement: **Does not meet High threshold**&quot;">​</a></h3><ul><li>SWE-bench Verified: highest-scoring at time of evaluation</li><li>OpenAI PRs: strongest performance among tested models</li><li>MLE-Bench: participated in evaluation</li></ul><hr><h2 id="red-teaming-results" tabindex="-1">Red Teaming Results <a class="header-anchor" href="#red-teaming-results" aria-label="Permalink to &quot;Red Teaming Results&quot;">​</a></h2><p><strong>Violent Attack Planning</strong> (25 expert red teamers):</p><ul><li>gpt-5-thinking rated <strong>safer 65.1% of the time vs. OpenAI o3</strong> (large effect size)</li></ul><p><strong>External Assessments</strong>:</p><ul><li>Microsoft AI Red Team: gpt-5-thinking showed &quot;one of the strongest AI safety profiles&quot; across 18 harm categories</li><li>Gray Swan prompt injection benchmark: state-of-the-art performance</li><li>SecureBio: mitigated versions refused all bioweaponization prompts</li></ul><hr><h2 id="health-domain" tabindex="-1">Health Domain <a class="header-anchor" href="#health-domain" aria-label="Permalink to &quot;Health Domain&quot;">​</a></h2><p><strong>HealthBench Hard</strong> — dramatic improvements:</p><table tabindex="0"><thead><tr><th>Model</th><th>Score</th></tr></thead><tbody><tr><td>gpt-5-thinking</td><td><strong>46.2%</strong></td></tr><tr><td>OpenAI o3</td><td>31.6%</td></tr></tbody></table><ul><li>Hallucinations: 8× reduction from o3</li><li>Urgent situation failures: 50× reduction from GPT-4o</li><li>Global health context failures: zero detected</li></ul><hr><h2 id="fairness-and-bias-bbq-evaluation" tabindex="-1">Fairness and Bias (BBQ Evaluation) <a class="header-anchor" href="#fairness-and-bias-bbq-evaluation" aria-label="Permalink to &quot;Fairness and Bias (BBQ Evaluation)&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Model</th><th>Ambiguous</th><th>Disambiguated</th></tr></thead><tbody><tr><td>gpt-5-thinking</td><td>0.95</td><td>0.85</td></tr><tr><td>gpt-5-main</td><td>0.93</td><td>0.86</td></tr></tbody></table><hr><h2 id="safeguards-implemented" tabindex="-1">Safeguards Implemented <a class="header-anchor" href="#safeguards-implemented" aria-label="Permalink to &quot;Safeguards Implemented&quot;">​</a></h2><p><strong>Multi-layered defense</strong>:</p><ul><li>Model-level training on refusal and safe completions</li><li>System-level protections and account-level enforcement</li><li>API access controls and Trusted Access Program</li><li>Multiple red teaming approaches including government-level assessments</li></ul><hr><h2 id="limitations-and-ongoing-challenges" tabindex="-1">Limitations and Ongoing Challenges <a class="header-anchor" href="#limitations-and-ongoing-challenges" aria-label="Permalink to &quot;Limitations and Ongoing Challenges&quot;">​</a></h2><ul><li>gpt-5-main regressions in certain content safety categories (hate/threatening, sexual/exploitative)</li><li>Instruction hierarchy vulnerabilities</li><li>Persistent deception risks despite mitigations</li><li>Reasoning model (CoT) transparency remains an open challenge</li></ul><hr><h2 id="workspace-relevance" tabindex="-1">Workspace Relevance <a class="header-anchor" href="#workspace-relevance" aria-label="Permalink to &quot;Workspace Relevance&quot;">​</a></h2><p>GPT-5&#39;s multi-model router architecture is the competitor reference for Anthropic&#39;s model selection in <code>haiku-pilot</code> / <code>sonnet-pilot</code> / <code>opus-pilot</code>. Key calibration points:</p><ul><li>GPT-5&#39;s unified routing (fast vs. reasoning) is analogous to the Haiku/Sonnet/Opus escalation gate in this workspace</li><li>gpt-5-thinking&#39;s 65% hallucination reduction vs o3 is the competitive bar for Claude Opus 4.7&#39;s hallucination profile (Claude Opus 4.7 max: 36% hallucination rate; GPT-5.5 at 86% per Artificial Analysis)</li><li>Safe-completions approach (maximize helpfulness within safety constraints) aligns with <code>core.md §R2 Simplicity First</code> — both prefer doing the task safely over refusing</li></ul><p>The HealthBench results (8× hallucination reduction) are relevant for any medical/clinical use case scenarios in <code>autoresearch</code> or <code>research-hub</code> tasks.</p>',60)])])}const m=t(n,[["render",o]]);export{p as __pageData,m as default};
